var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨! 대체 무슨 짓이야!","JPN":"おじさん！　いったいどういうこと！？","ENG":"Mr. Mason, what were you thinking?!","TWN":"大叔！你這是在幹嘛啦！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"수송기에서 그대로 던져 버리다니, 죽는 줄 알았잖아!","JPN":"輸送機からそのまま投げ飛ばすなんて、死ぬかと思ったじゃん！","ENG":"You just threw us out of the ship! We could have died!","TWN":"竟然就那樣從貨機上一躍而下，我還以為你們會死掉！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 덕분에 침식체의 위협에서 안전해졌지.","JPN":"だがおかげで侵食体の脅威から守られたぞ。","ENG":"Yet here we are, safe and sound from the threat of the C.O.s.","TWN":"起碼我們脫離侵蝕體的威脅啦！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"애초에 너희들이니까 할 수 있다고 생각한 거야.","JPN":"あんたらのことだから最初からできると信じてたんだよ。","ENG":"I believed in you guys.","TWN":"因為是你們，我們才敢放心跳的嘛！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"음? 잠깐, 저 빛은 뭐지?","JPN":"うん？　待て、あの光は何だ？","ENG":"Huh? What’s that light?","TWN":"嗯？先等一下，那個光是怎麼回事？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"말 돌리지 말고……!","JPN":"ねえ、話を逸らさない……！","ENG":"Don’t try to switch the subject—","TWN":"不要轉移話題……！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"엎드려!","JPN":"伏せろ！","ENG":"Get down!","TWN":"趴下！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야?","JPN":"な、何？","ENG":"W-what’s that?","TWN":"幹嘛？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대령! 설마 저건가?","JPN":"大佐！　まさかアレか？","ENG":"Colonel, is that it?!","TWN":"上校！是那個嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"……그래. 등대의 빛인 것 같아.","JPN":"……ああ。灯台の光のようだ。","ENG":"... Yes, it must be from the Lighthouse.","TWN":"……沒錯，應該是燈塔的光。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 위력만 봐선 함선급 광선 무기에 더 가까운 것 같은데요.","JPN":"ですが、威力だけ見れば艦船級の光線兵器に近いようですが。","ENG":"But that almost looks like a laser shot from a battleship.","TWN":"但威力感覺接近艦船等級的光束武器？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"등대라는 게 원래 저런 고출력 광선을 발사하는 물건인가요?","JPN":"灯台というのは元々あんな高出力光線を放つものなんですか？","ENG":"Is that what the Lighthouse is supposed to do, emit a high-power beam?","TWN":"燈塔原本就會發射高輸出的光束嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아니. 내가 봤던 등대는 평범한 신호기였어.","JPN":"いや、俺が見た灯台は普通の信号機だった。","ENG":"No, the Lighthouse I saw was a common signal transmitter.","TWN":"不，我看過的燈塔就只是一個單純的信號器。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차원 폭풍도 뚫을 수 있는 특별한 신호를 발산하긴 했지만, 이 정도로 강력하지는 않았는데…….","JPN":"次元の暴風を突破できる特別な信号を発信していたが、\\nこれほど強力ではなかったはず……","ENG":"The signal was strong enough to make it through the storm, but not that strong...","TWN":"雖然是可以發射穿透次元風暴的特殊信號，但威力不至於這麼大……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……이거 불길한 예상이 떠오르는군.","JPN":"……これは嫌な予感しかしないな。","ENG":"I have a bad feeling about this.","TWN":"……我有種不好的預感！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"불길한 예상?","JPN":"嫌な予感？","ENG":"A bad feeling?","TWN":"不好的預感？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};